{
  "name": "BrandGenius AI - Branding Expert",
  "description": "Une plateforme d'agence de branding haut de gamme alimentée par l'IA pour créer des identités visuelles professionnelles et des chartes graphiques complètes."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BrandProfile {
  companyName: string;
  industry: string;
  mission: string;
  values: string;
  targetAudience: string;
  positioning: string;
  preferences: string;
}

export interface BrandingResult {
  logo: {
    concept: string;
    type: string;
    symbolism: string;
    description: string;
    variations: {
      color: string;
      black: string;
      white: string;
      backgrounds: string;
    };
  };
  styleGuide: {
    colors: Array<{
      hex: string;
      name: string;
      usage: string;
    }>;
    typography: {
      titles: {
        fontFamily: string;
        usage: string;
      };
      body: {
        fontFamily: string;
        usage: string;
      };
    };
    rules: string[];
    visualStyle: string;
    applications: {
      socialMedia: string;
      flyers: string;
      businessCards: string;
      website: string;
    };
  };
}

import { GoogleGenAI, Type } from "@google/genai";
import { BrandProfile, BrandingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const prompt = `
    En tant qu'expert en branding haut de gamme, génère une identité visuelle complète pour l'entreprise suivante :
    Nom : ${profile.companyName}
    Secteur : ${profile.industry}
    Mission : ${profile.mission}
    Valeurs : ${profile.values}
    Cible : ${profile.targetAudience}
    Positionnement : ${profile.positioning}
    Préférences : ${profile.preferences}

    Réponds STRICTEMENT en format JSON suivant le schéma fourni.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              variations: {
                type: Type.OBJECT,
                properties: {
                  color: { type: Type.STRING },
                  black: { type: Type.STRING },
                  white: { type: Type.STRING },
                  backgrounds: { type: Type.STRING },
                },
                required: ["color", "black", "white", "backgrounds"],
              },
            },
            required: ["concept", "type", "symbolism", "description", "variations"],
          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                },
                required: ["titles", "body"],
              },
              rules: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              visualStyle: { type: Type.STRING },
              applications: {
                type: Type.OBJECT,
                properties: {
                  socialMedia: { type: Type.STRING },
                  flyers: { type: Type.STRING },
                  businessCards: { type: Type.STRING },
                  website: { type: Type.STRING },
                },
                required: ["socialMedia", "flyers", "businessCards", "website"],
              },
            },
            required: ["colors", "typography", "rules", "visualStyle", "applications"],
          },
        },
        required: ["logo", "styleGuide"],
      },
    },
  });

  if (!response.text) {
    throw new Error("Aucune réponse générée");
  }

  return JSON.parse(response.text.trim());
};

