import React, { useState } from 'react';
import { BrandProfile } from '../types';

interface InputFormProps {
  onSubmit: (profile: BrandProfile) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [profile, setProfile] = useState<BrandProfile>({
    companyName: '',
    industry: '',
    mission: '',
    values: '',
    targetAudience: '',
    positioning: '',
    preferences: '',
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setProfile(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(profile);
  };

  const inputClasses = "w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none";
  const labelClasses = "block text-sm font-semibold text-gray-700 mb-1.5 ml-1";

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-3xl shadow-xl shadow-gray-100 p-8 space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className={labelClasses}>Nom de l'entreprise</label>
          <input
            required
            name="companyName"
            value={profile.companyName}
            onChange={handleChange}
            placeholder="Ex: Luminia Tech"
            className={inputClasses}
          />
        </div>
        <div>
          <label className={labelClasses}>Secteur d'activité</label>
          <input
            required
            name="industry"
            value={profile.industry}
            onChange={handleChange}
            placeholder="Ex: Énergie solaire résidentielle"
            className={inputClasses}
          />
        </div>
      </div>

      <div>
        <label className={labelClasses}>Mission / Vision</label>
        <textarea
          required
          name="mission"
          value={profile.mission}
          onChange={handleChange}
          rows={3}
          placeholder="Quelle est la raison d'être de votre entreprise ?"
          className={inputClasses}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className={labelClasses}>Valeurs clés</label>
          <input
            required
            name="values"
            value={profile.values}
            onChange={handleChange}
            placeholder="Ex: Innovation, Transparence, Écologie"
            className={inputClasses}
          />
        </div>
        <div>
          <label className={labelClasses}>Positionnement souhaité</label>
          <select
            name="positioning"
            value={profile.positioning}
            onChange={handleChange}
            className={inputClasses}
          >
            <option value="Luxe / Haut de gamme">Luxe / Haut de gamme</option>
            <option value="Moderne / Technologique">Moderne / Technologique</option>
            <option value="Accessible / Familial">Accessible / Familial</option>
            <option value="Institutionnel / Sérieux">Institutionnel / Sérieux</option>
            <option value="Minimaliste / Épuré">Minimaliste / Épuré</option>
            <option value="Créatif / Audacieux">Créatif / Audacieux</option>
          </select>
        </div>
      </div>

      <div>
        <label className={labelClasses}>Cible principale</label>
        <input
          required
          name="targetAudience"
          value={profile.targetAudience}
          onChange={handleChange}
          placeholder="Qui sont vos clients idéaux ?"
          className={inputClasses}
        />
      </div>

      <div>
        <label className={labelClasses}>Préférences ou Interdictions</label>
        <input
          name="preferences"
          value={profile.preferences}
          onChange={handleChange}
          placeholder="Couleurs préférées, symboles à éviter, etc."
          className={inputClasses}
        />
      </div>

      <button
        type="submit"
        disabled={isLoading}
        className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-200 transition-all flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
      >
        {isLoading ? (
          <>
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Analyse stratégique en cours...
          </>
        ) : "Générer l'Identité Visuelle Professionnelle"}
      </button>
    </form>
  );
};

export default InputForm;

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
