  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (profile: BrandProfile) => {
    setIsLoading(true);
    setError(null);
    try {
      const brandingData = await generateBranding(profile);
      setResult(brandingData);
      // Scroll to result
      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Une erreur s'est produite lors de la génération. Veuillez vérifier vos informations ou réessayer plus tard.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Header />

      <main className="max-w-6xl mx-auto px-4 pb-20">
        <div className="text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-serif text-gray-900 mb-4">
