          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
