import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import BrandingResult from './components/BrandingResult';
import { BrandProfile, BrandingResult as BrandingType } from './types';
import { generateBranding, generateImage } from './services/geminiService';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Analyse stratégique et création textuelle...");
    setError(null);
    try {
      // Step 1: Text Branding
      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');

      // Step 2: Main Logo
      setLoadingStep("Conception visuelle du logo principal...");
      const logoPrompt = `High-end professional minimal logo for "${brandProfile.companyName}" in the "${brandProfile.industry}" sector. Style: ${brandProfile.positioning}. Colors: ${colorString}. Description: ${brandingData.logo.description}. White background, studio lighting, vector style.`;
      const logoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = logoUrl;

      // Step 3: Variations
      setLoadingStep("Création des variations (Simplifié, Monochrome, Favicon)...");

      // Simplified
      const simplifiedPrompt = `Simplified minimalist vector logo version for "${brandProfile.companyName}". Clean shapes, no gradients, high contrast, white background. Colors: ${colorString}.`;
      brandingData.logo.simplifiedImageUrl = await generateImage(simplifiedPrompt);

      // Monochrome
      const monochromePrompt = `Flat black and white monochrome logo for "${brandProfile.companyName}". Strictly solid black on pure white background, no gray, vector silhouette.`;
      brandingData.logo.monochromeImageUrl = await generateImage(monochromePrompt);

      // Favicon
      const faviconPrompt = `Minimalist icon favicon for "${brandProfile.companyName}". Bold geometric symbol, square format, high legibility at small size, white background. Colors: ${colorString}.`;
      brandingData.logo.faviconImageUrl = await generateImage(faviconPrompt);

      // Step 4: Mockup
      setLoadingStep("Génération des mises en situation professionnelles...");
      const mockupPrompt = `Professional premium branding mockup for "${brandProfile.companyName}". Includes business cards and stationery on a clean desk. Style: ${brandingData.styleGuide.visualStyle}. Use colors: ${colorString}. Elegant composition, photorealistic, cinematic lighting.`;
      const mockupUrl = await generateImage(mockupPrompt);
      brandingData.styleGuide.mockupImageUrl = mockupUrl;

      setResult(brandingData);

      // Scroll to result
      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Une erreur s'est produite lors de la génération. Veuillez vérifier vos informations ou réessayer plus tard.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Header />

      <main className="max-w-6xl mx-auto px-4 pb-20">
        <div className="text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-serif text-gray-900 mb-4">
            L'Identité de votre Succès
          </h2>
          <p className="text-gray-500 text-lg max-w-2xl mx-auto">
            Décrivez votre entreprise et laissez notre intelligence créative concevoir une image de marque digne des plus grandes agences de design.
          </p>
        </div>

        <div className="max-w-4xl mx-auto mb-16">
          <InputForm onSubmit={handleGenerate} isLoading={isLoading} />

          {isLoading && (
            <div className="mt-4 flex flex-col items-center">
              <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-3"></div>
              <p className="text-indigo-600 font-medium">{loadingStep}</p>
            </div>
          )}

          {error && (
            <div className="mt-6 p-4 bg-red-50 border border-red-100 text-red-600 rounded-xl text-center font-medium">
              {error}
            </div>
          )}
        </div>

        {result && (
          <div id="result-section">
            <BrandingResult 
              data={result} 
              onUpdateMockups={handleUpdateMockups}
              companyName={profile?.companyName || ""}
            />
          </div>
        )}

        {!result && !isLoading && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-12 opacity-50">
            <div className="p-6 bg-white rounded-2xl border border-gray-100 text-center">
              <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.674M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
              </div>
              <h3 className="font-bold text-gray-900">Concept Créatif</h3>
              <p className="text-sm text-gray-500">Une réflexion profonde sur l'âme de votre marque.</p>
            </div>
            <div className="p-6 bg-white rounded-2xl border border-gray-100 text-center">
              <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01"></path></svg>
              </div>
              <h3 className="font-bold text-gray-900">Charte Graphique</h3>
              <p className="text-sm text-gray-500">Couleurs et typographies sélectionnées avec soin.</p>
            </div>
            <div className="p-6 bg-white rounded-2xl border border-gray-100 text-center">
              <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              </div>
              <h3 className="font-bold text-gray-900">Dossier de Marque</h3>
              <p className="text-sm text-gray-500">Un document prêt à être utilisé par vos équipes.</p>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-gray-100 py-12 px-4 print:hidden">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center text-sm text-gray-400">
          <p>© 2024 BrandGenius AI. L'excellence du design par l'IA.</p>
          <div className="flex space-x-6 mt-4 md:mt-0">
            <a href="#" className="hover:text-indigo-600">Conditions d'utilisation</a>
            <a href="#" className="hover:text-indigo-600">Politique de confidentialité</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

