const App: React.FC = () => {
  const [step, setStep] = useState<'input' | 'orientations' | 'loading' | 'result'>('input');
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [orientations, setOrientations] = useState<CreativeOrientation[]>([]);
  const [selectedOrientation, setSelectedOrientation] = useState<CreativeOrientation | null>(null);
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);

  const handleStartAnalysis = async (brandProfile: BrandProfile) => {
    setStep('loading');
    setLoadingStep("Diagnostic de marque en cours...");
    setProfile(brandProfile);
    setError(null);
    try {
      const proposals = await generateOrientations(brandProfile);
      setOrientations(proposals);
      setStep('orientations');
    } catch (err) {
      console.error(err);
      setError("Erreur lors de l'analyse stratégique. Veuillez réessayer.");
      setStep('input');
    }
  };

  const handleSelectOrientation = async (orientation: CreativeOrientation) => {
    if (!profile) return;
    setSelectedOrientation(orientation);
    setStep('loading');
    setLoadingStep(`Production de l'identité : ${orientation.title}...`);

    try {
      // Step 1: Text Branding
      const brandingData = await generateBranding(profile, orientation);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');

      // Step 2: Visual Production
      setLoadingStep("Génération du concept visuel principal...");
      const logoPrompt = `High-end professional minimal logo for "${profile.companyName}". Concept: ${brandingData.logo.concept}. Colors: ${colorString}. White background, professional studio design.`;
      brandingData.logo.generatedImageUrl = await generateImage(logoPrompt);

      setLoadingStep("Optimisation des déclinaisons (Simplified, Favicon, Avatar)...");
      const faviconPrompt = `Minimalist icon symbol from logo of "${profile.companyName}". Bold shape, high legibility. Colors: ${colorString}.`;
      brandingData.logo.faviconImageUrl = await generateImage(faviconPrompt);
      brandingData.logo.socialAvatarUrl = await generateImage(`Professional social media profile avatar for "${profile.companyName}". Center aligned, balanced.`);

      setLoadingStep("Mise en situation premium...");
      const mockupPrompt = `Professional premium branding mockup for "${profile.companyName}" showing business card and stationery. Elegant lighting, high contrast. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt);

      setResult(brandingData);
      setStep('result');

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Erreur lors de la production visuelle. Veuillez réessayer.");
      setStep('orientations');
    }
  };

  return (
    <div className="min-h-screen relative overflow-x-hidden">
      {/* Background Decor */}
