          <p className="text-blue-100/90 text-lg md:text-2xl max-w-2xl mx-auto font-light leading-relaxed">
            Élevez votre business au rang de marque iconique avec le processus itératif de notre Direction Artistique Senior.
          </p>
        </div>

        {step === 'input' && (
          <div className="max-w-4xl mx-auto mb-16 animate-in fade-in duration-500">
            <InputForm onSubmit={handleStartAnalysis} isLoading={false} />
            {error && <div className="mt-8 p-6 bg-red-50 text-red-600 rounded-2xl text-center font-bold shadow-xl">{error}</div>}
          </div>
        )}

        {step === 'loading' && (
          <div className="max-w-4xl mx-auto mt-10 flex flex-col items-center bg-indigo-900/40 backdrop-blur-xl rounded-3xl p-10 border border-white/10 shadow-2xl animate-in fade-in duration-500">
            <div className="w-16 h-16 border-4 border-blue-300/20 border-t-blue-400 rounded-full animate-spin mb-6"></div>
            <p className="text-blue-200 text-2xl font-bold tracking-wide animate-pulse">{loadingStep}</p>
            <p className="text-blue-300/40 text-sm mt-3 uppercase tracking-widest font-bold italic">La qualité exige de la patience...</p>
          </div>
        )}

        {step === 'orientations' && (
          <div className="max-w-6xl mx-auto animate-in slide-in-from-bottom-10 duration-700">
            <div className="text-center mb-10">
              <span className="px-4 py-1 bg-blue-500/20 rounded-full text-blue-300 text-xs font-bold uppercase tracking-widest border border-blue-500/30">Étape 2 : Stratégie Visuelle</span>
