                </button>
              ))}
            </div>
          </div>
        )}

        {step === 'result' && result && (
          <div id="result-section" className="mt-20">
            <BrandingResult 
              data={result} 
              onUpdateMockups={(mockups) => setResult({...result, styleGuide: {...result.styleGuide, extraMockups: mockups}})}
              companyName={profile?.companyName || ""}
            />
          </div>
