      <footer className="bg-white/80 backdrop-blur-md border-t border-blue-100 py-12 px-4 print:hidden relative z-10">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center text-sm text-indigo-950/60">
