import { GoogleGenAI, Type } from "@google/genai";
import { BrandProfile, BrandingResult, CreativeOrientation } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SYSTEM_PERSONA = `
Tu es une IA de branding et d'identité visuelle fonctionnant comme un Directeur Artistique Senior avec plus de 20 ans d'expérience. 
Ton style est celui des agences internationales haut de gamme : sobriété, clarté, force visuelle et intemporalité. 
Tu refuses le générique et privilégies la crédibilité stratégique.
`;

export const generateOrientations = async (profile: BrandProfile): Promise<CreativeOrientation[]> => {
  const prompt = `
    ${SYSTEM_PERSONA}

    ÉTAPE : ORIENTATION CRÉATIVE
    Basé sur ce profil business, propose 3 orientations visuelles professionnelles distinctes.

    Profil :
    - Nom : ${profile.companyName}
    - Secteur : ${profile.industry}
    - Mission : ${profile.mission}
    - Valeurs : ${profile.values}
    - Cible : ${profile.targetAudience}
    - Positionnement : ${profile.positioning}

    Format de réponse : JSON (ARRAY d'objets avec id, title, style, message, targetAppeal).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            style: { type: Type.STRING },
            message: { type: Type.STRING },
            targetAppeal: { type: Type.STRING },
          },
          required: ["id", "title", "style", "message", "targetAppeal"],
        },
      },
    },
  });

  return JSON.parse(response.text || "[]");
};

export const generateBranding = async (profile: BrandProfile, orientation: CreativeOrientation): Promise<BrandingResult> => {
  const prompt = `
    ${SYSTEM_PERSONA}

    ÉTAPE : CONCEPTION FINALE DU LOGO ET CHARTE GRAPHIQUE
    Tu dois maintenant produire l'identité complète basée sur l'orientation choisie : "${orientation.title}" (${orientation.style}).

    Entreprise : ${profile.companyName}
    Mode de rendu : ${profile.mode === 'expert' ? 'Détaillé et hautement stratégique' : 'Clair et accessible'}

    Inclus également un score de crédibilité (0-100) et des recommandations stratégiques pour le futur de la marque.

    Réponds STRICTEMENT en format JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              variations: {
                type: Type.OBJECT,
                properties: {
                  color: { type: Type.STRING },
                  black: { type: Type.STRING },
                  white: { type: Type.STRING },
                  backgrounds: { type: Type.STRING },
                },
                required: ["color", "black", "white", "backgrounds"],
              },
            },
            required: ["concept", "type", "symbolism", "description", "variations"],
          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                },
                required: ["titles", "body"],
              },
              rules: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              visualStyle: { type: Type.STRING },
              applications: {
                type: Type.OBJECT,
                properties: {
                  socialMedia: { type: Type.STRING },
                  flyers: { type: Type.STRING },
                  businessCards: { type: Type.STRING },
                  website: { type: Type.STRING },
                },
                required: ["socialMedia", "flyers", "businessCards", "website"],
              },
            },
            required: ["colors", "typography", "rules", "visualStyle", "applications"],
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              credibilityScore: { type: Type.NUMBER },
              futureRecommendations: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["credibilityScore", "futureRecommendations"]
          }
        },
        required: ["logo", "styleGuide", "analysis"],
      },
    },
  });

  return JSON.parse(response.text || "{}");
};

export const generateImage = async (prompt: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `Professional high-end minimalist graphic design: ${prompt}. Clean background, studio lighting, premium aesthetic.` }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Impossible de générer l'image visuelle.");
};

