import { GoogleGenAI, Type } from "@google/genai";
import { BrandProfile, BrandingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SYSTEM_INSTRUCTION = `
Tu es un Directeur Artistique Senior d'une agence de branding de luxe. 
Ton objectif est de créer des identités visuelles intemporelles, sobres et puissantes. 
Tu évites les clichés et privilégies la clarté stratégique. 
Chaque choix (couleur, typo, symbole) doit être justifié par le positionnement du client.
`;

export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const prompt = `
    Génère une identité visuelle complète et haut de gamme.
    Entreprise : ${profile.companyName}
    Secteur : ${profile.industry}
    Mission : ${profile.mission}
    Valeurs : ${profile.values}
    Cible : ${profile.targetAudience}
    Positionnement : ${profile.positioning}
    Préférences : ${profile.preferences}

    Réponds en JSON avec un score de crédibilité (0-100) et 3 recommandations stratégiques.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              variations: {
                type: Type.OBJECT,
                properties: {
                  color: { type: Type.STRING },
                  black: { type: Type.STRING },
                  white: { type: Type.STRING },
                  backgrounds: { type: Type.STRING },
                },
                required: ["color", "black", "white", "backgrounds"],
              },
            },
            required: ["concept", "type", "symbolism", "description", "variations"],
          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage"],
                  },
                },
                required: ["titles", "body"],
              },
              rules: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              visualStyle: { type: Type.STRING },
              applications: {
                type: Type.OBJECT,
                properties: {
                  socialMedia: { type: Type.STRING },
                  flyers: { type: Type.STRING },
                  businessCards: { type: Type.STRING },
                  website: { type: Type.STRING },
                },
                required: ["socialMedia", "flyers", "businessCards", "website"],
              },
            },
            required: ["colors", "typography", "rules", "visualStyle", "applications"],
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              credibilityScore: { type: Type.NUMBER },
              futureRecommendations: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["credibilityScore", "futureRecommendations"]
          }
        },
        required: ["logo", "styleGuide", "analysis"],
      },
    },
  });

  return JSON.parse(response.text.trim());
};

export const generateImage = async (prompt: string, base64ReferenceImage?: string): Promise<string> => {
  const parts: any[] = [{ text: prompt }];

  if (base64ReferenceImage) {
    const cleanBase64 = base64ReferenceImage.replace(/^data:image\/\w+;base64,/, "");
    parts.unshift({
      inlineData: {
        mimeType: 'image/png',
        data: cleanBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: parts,
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Erreur de génération d'image.");
};

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
