const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Établissement du diagnostic stratégique...");
    setError(null);
    try {
      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');

      setLoadingStep("Conception du logotype maître...");
      const logoPrompt = `High-end professional minimal vector logo for "${brandProfile.companyName}". Style: ${brandProfile.positioning}. Colors: ${colorString}. Central mark: ${brandingData.logo.description}. Isolated on white background, sharp lines, premium aesthetic.`;
      const masterLogoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = masterLogoUrl;

      setLoadingStep("Application du logo sur les supports de marque...");

      const simplifiedPrompt = `SIMPLIFIED VERSION: Take the EXACT visual mark from the provided image and create a minimalist version for small scale. Maintain the same geometric shape. Pure white background.`;
      brandingData.logo.simplifiedImageUrl = await generateImage(simplifiedPrompt, masterLogoUrl);

      const monochromePrompt = `MONOCHROME VERSION: Transform the ATTACHED logo into a solid black silhouette. No colors, no gradients, identical shape. Pure white background.`;
      brandingData.logo.monochromeImageUrl = await generateImage(monochromePrompt, masterLogoUrl);

      const faviconPrompt = `FAVICON: Extract the core symbol from the ATTACHED logo. High contrast, perfectly centered for a square app icon. Colors: ${colorString}.`;
      brandingData.logo.faviconImageUrl = await generateImage(faviconPrompt, masterLogoUrl);

      setLoadingStep("Génération des mockups premium...");
      const mockupPrompt = `PREMIUM MOCKUP: Place the EXACT ATTACHED LOGO as the main branding element on high-quality business cards and stationery. The logo must be clearly visible and identical to the source. Style: ${brandingData.styleGuide.visualStyle}. Lighting: Studio. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt, masterLogoUrl);

      setResult(brandingData);

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Désolé, une erreur technique est survenue. Veuillez réessayer.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
  };

  return (
    <div className="min-h-screen relative overflow-x-hidden">
      <div className="absolute top-0 left-0 w-full h-[600px] bg-indigo-950 overflow-hidden -z-10 skew-y-[-2deg] origin-top-left border-b-8 border-blue-500/20">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-950 via-indigo-900 to-blue-900 opacity-95"></div>
      </div>

      <Header />

      <main className="max-w-6xl mx-auto px-4 pb-20 relative z-10">
        <div className="text-center mb-12 py-10">
          <h2 className="text-5xl md:text-7xl font-serif text-blue-400 mb-6 drop-shadow-lg font-extrabold">
            Dossier de <span className="text-white">Marque</span>
          </h2>
          <p className="text-blue-100/90 text-lg md:text-2xl max-w-2xl mx-auto font-light leading-relaxed">
            Une identité visuelle d'exception, conçue par un Directeur Artistique Senior alimenté par l'IA.
          </p>
        </div>

        <div className="max-w-4xl mx-auto mb-16">
          <InputForm onSubmit={handleGenerate} isLoading={isLoading} />

          {isLoading && (
            <div className="mt-10 flex flex-col items-center bg-indigo-900/40 backdrop-blur-xl rounded-3xl p-10 border border-white/10 shadow-2xl">
              <div className="w-16 h-16 border-4 border-blue-300/20 border-t-blue-400 rounded-full animate-spin mb-6"></div>
              <p className="text-blue-200 text-2xl font-bold tracking-wide animate-pulse">{loadingStep}</p>
              <p className="text-blue-300/40 text-sm mt-3 uppercase tracking-widest font-bold">Cohérence Visuelle Garantie</p>
            </div>
          )}

          {error && (
            <div className="mt-8 p-6 bg-red-50/90 backdrop-blur-sm border border-red-200 text-red-600 rounded-2xl text-center font-bold shadow-xl">
              {error}
            </div>
          )}
        </div>

        {result && (
          <div id="result-section" className="mt-20">
            <BrandingResult 
              data={result} 
              onUpdateMockups={handleUpdateMockups}
              companyName={profile?.companyName || ""}
            />
          </div>
