import { GoogleGenAI, Type } from "@google/genai";
import { BrandProfile, BrandingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SYSTEM_INSTRUCTION = `
Tu es un Directeur Artistique Senior et Expert Technique en Design Graphique. 
Ton objectif est de créer des identités visuelles intemporelles et techniquement parfaites. 
Tu dois fournir des spécifications précises pour les designers (Photoshop/Affinity/Canva).
Chaque couleur doit avoir ses équivalents RGB et CMYK réalistes.
Les motifs graphiques doivent renforcer l'ADN de la marque.
`;

export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const prompt = `
    Génère un dossier de branding complet et professionnel.
    Entreprise : ${profile.companyName}
    Secteur : ${profile.industry}
    Positionnement : ${profile.positioning}

    Instructions spécifiques :
    - Calcule des codes RGB et CMYK cohérents avec les HEX.
    - Définis un concept de motif graphique (pattern) secondaire.
    - Liste des règles d'utilisation strictes (Autorisé vs Interdit).

    Réponds en JSON uniquement.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              variations: {
                type: Type.OBJECT,
                properties: {
                  color: { type: Type.STRING },
                  black: { type: Type.STRING },
                  white: { type: Type.STRING },
                  backgrounds: { type: Type.STRING },
                },
                required: ["color", "black", "white", "backgrounds"],
              },
            },
            required: ["concept", "type", "symbolism", "description", "variations"],
          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    rgb: { type: Type.STRING },
                    cmyk: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "rgb", "cmyk", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                      style: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage", "style"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                      style: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage", "style"],
                  },
                },
                required: ["titles", "body"],
              },
              graphicElements: {
                type: Type.OBJECT,
                properties: {
                  patternConcept: { type: Type.STRING },
                  textureDescription: { type: Type.STRING },
                },
                required: ["patternConcept", "textureDescription"],
              },
              rules: {
                type: Type.OBJECT,
                properties: {
                  allowed: { type: Type.ARRAY, items: { type: Type.STRING } },
                  forbidden: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["allowed", "forbidden"],
              },
              visualStyle: { type: Type.STRING },
              applications: {
                type: Type.OBJECT,
                properties: {
                  socialMedia: { type: Type.STRING },
                  flyers: { type: Type.STRING },
                  businessCards: { type: Type.STRING },
                  website: { type: Type.STRING },
                },
                required: ["socialMedia", "flyers", "businessCards", "website"],
              },
            },
            required: ["colors", "typography", "graphicElements", "rules", "visualStyle", "applications"],
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              credibilityScore: { type: Type.NUMBER },
              futureRecommendations: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["credibilityScore", "futureRecommendations"]
          }
        },
        required: ["logo", "styleGuide", "analysis"],
      },
    },
  });

  return JSON.parse(response.text.trim());
};

export const generateImage = async (prompt: string, base64ReferenceImage?: string): Promise<string> => {
  const parts: any[] = [{ text: prompt }];

  if (base64ReferenceImage) {
    const cleanBase64 = base64ReferenceImage.replace(/^data:image\/\w+;base64,/, "");
    parts.unshift({
      inlineData: {
        mimeType: 'image/png',
        data: cleanBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: parts,
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Erreur de génération d'image.");
};

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
