const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Analyse stratégique et codage technique...");
    setError(null);
    try {
      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');

      setLoadingStep("Création du logotype maître...");
      const logoPrompt = `High-end professional minimal vector logo for "${brandProfile.companyName}". Colors: ${colorString}. Symbol: ${brandingData.logo.description}. Pure white background, high contrast, source file style.`;
      const masterLogoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = masterLogoUrl;

      setLoadingStep("Génération du motif graphique exclusif...");
      const patternPrompt = `Seamless professional high-end geometric pattern for "${brandProfile.companyName}". Concept: ${brandingData.styleGuide.graphicElements.patternConcept}. Use colors: ${colorString}. Flat design, repeat style.`;
      brandingData.styleGuide.graphicElements.patternImageUrl = await generateImage(patternPrompt, masterLogoUrl);

      setLoadingStep("Déclinaisons techniques et mockups...");

      const simplifiedPrompt = `SIMPLIFIED LOGO: Take the central symbol from the ATTACHED image. Minimalist flat vector on pure white background.`;
      brandingData.logo.simplifiedImageUrl = await generateImage(simplifiedPrompt, masterLogoUrl);

      const monochromePrompt = `MONOCHROME LOGO: Identical shape to ATTACHED but in pure solid black on white background. No shades.`;
      brandingData.logo.monochromeImageUrl = await generateImage(monochromePrompt, masterLogoUrl);

      const faviconPrompt = `FAVICON: Core icon from the ATTACHED image. Centered, high legibility.`;
      brandingData.logo.faviconImageUrl = await generateImage(faviconPrompt, masterLogoUrl);

      const mockupPrompt = `PREMIUM BRANDING MOCKUP: Show the ATTACHED logo and pattern on stationery and business cards. Professional lighting. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt, masterLogoUrl);

      setResult(brandingData);

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Une erreur est survenue. Veuillez vérifier votre clé API ou vos entrées.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
