import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;
    const element = contentRef.current;
    const opt = {
      margin: 0,
      filename: `BrandBook_${companyName.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };
    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  const handleDownloadSourcePack = async () => {
    setIsZipping(true);
    try {
      const zip = new JSZip();
      const assets = zip.folder("01_Assets_Visuels");
      const specs = zip.folder("02_Specs_Techniques");

      const addImage = (base64: string | undefined, name: string) => {
        if (!base64) return;
        assets?.file(`${name}.png`, base64.split(',')[1], { base64: true });
      };

      addImage(data.logo.generatedImageUrl, "LOGO_MASTER");
      addImage(data.logo.simplifiedImageUrl, "LOGO_SIMPLIFIED");
      addImage(data.logo.monochromeImageUrl, "LOGO_MONOCHROME");
      addImage(data.logo.faviconImageUrl, "FAVICON");
      addImage(data.styleGuide.graphicElements.patternImageUrl, "PATTERN_TEXTURE");
      addImage(data.styleGuide.mockupImageUrl, "MOCKUP_CONCEPT");

      const designSystem = {
        identity: companyName,
        colors: data.styleGuide.colors,
        typography: data.styleGuide.typography,
        rules: data.styleGuide.rules,
        exportDate: new Date().toISOString()
      };

      specs?.file("design_system.json", JSON.stringify(designSystem, null, 2));

      const instructions = `
GUIDE TECHNIQUE - RECONSTRUCTION DES FICHIERS SOURCE
===================================================
Client: ${companyName}

1. CONFIGURATION DU DOCUMENT (Photoshop/Affinity)
   - Print: 300 DPI, Mode CMYK (Profil Coated FOGRA39 conseillé)
   - Digital: 72 DPI, Mode RGB (Profil sRGB)

2. COULEURS TECHNIQUES
${data.styleGuide.colors.map(c => `   [ ${c.name} ]
   - HEX: ${c.hex}
   - RGB: ${c.rgb}
   - CMYK: ${c.cmyk}
   - Usage: ${c.usage}`).join('\n\n')}

3. TYPOGRAPHIES
   - Primaire: ${data.styleGuide.typography.titles.fontFamily} (${data.styleGuide.typography.titles.style})
   - Secondaire: ${data.styleGuide.typography.body.fontFamily} (${data.styleGuide.typography.body.style})

4. MOTIF GRAPHIQUE
   - Utilisez le fichier "PATTERN_TEXTURE.png" comme masque d'écrêtage ou motif de fond à 10-20% d'opacité pour créer du relief.

Généré par BrandGenius AI Master - Suite Expert.
      `;
      specs?.file("INSTRUCTIONS_RECONSTRUCTION.txt", instructions);

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(content);
      link.download = `Pack_Source_${companyName.replace(/\s+/g, '_')}.zip`;
      link.click();
    } catch (err) {
      console.error(err);
      alert("Erreur lors de la préparation du pack source.");
    } finally {
      setIsZipping(false);
    }
  };

  const generateExtraMockups = async () => {
    if (!data.logo.generatedImageUrl) return;
    setIsGeneratingMockups(true);
    try {
      const colorString = data.styleGuide.colors.map(c => c.hex).join(', ');
      const prompts = [
        `MOCKUP: Logo on high-end glass building. Colors: ${colorString}.`,
        `MOCKUP: Logo on luxury packaging. Colors: ${colorString}.`,
        `MOCKUP: Logo on digital iPhone app interface. Colors: ${colorString}.`
      ];
      const results = await Promise.all(prompts.map(p => generateImage(p, data.logo.generatedImageUrl)));
      if (onUpdateMockups) onUpdateMockups(results);
    } catch (err) {
