import { GoogleGenAI, Type } from "@google/genai";
import { BrandProfile, BrandingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SYSTEM_INSTRUCTION = `
Tu es un Directeur Artistique Senior et Ingénieur Design. 
Ton objectif est de créer des identités visuelles intemporelles et techniquement parfaites. 
Tu dois fournir des spécifications précises pour les designers (Photoshop/Affinity/Canva/Illustrator).
Chaque couleur doit avoir ses équivalents RGB et CMYK réalistes.
Les motifs graphiques doivent renforcer l'ADN de la marque.
Tu dois également fournir un code SVG simplifié (path) représentant le symbole central de la marque pour permettre une reconstruction vectorielle propre.
`;

export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const prompt = `
    Génère un dossier de branding complet, professionnel et technique.
    Entreprise : ${profile.companyName}
    Secteur : ${profile.industry}
    Positionnement : ${profile.positioning}

    Instructions spécifiques :
    - Calcule des codes RGB et CMYK cohérents.
    - Définis un concept de motif graphique (pattern).
    - Fournis un chemin SVG (string) très simple pour le symbole central du logo (ex: <path d="..." />).
    - Liste des règles d'utilisation strictes.

    Réponds en JSON uniquement.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              svgPath: { type: Type.STRING, description: "Code SVG simplifié du symbole central" },
              variations: {
                type: Type.OBJECT,
                properties: {
                  color: { type: Type.STRING },
                  black: { type: Type.STRING },
                  white: { type: Type.STRING },
                  backgrounds: { type: Type.STRING },
                },
                required: ["color", "black", "white", "backgrounds"],
              },
            },
            required: ["concept", "type", "symbolism", "description", "variations"],
          },
          styleGuide: {
            type: Type.OBJECT,
            properties: {
              colors: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    hex: { type: Type.STRING },
                    name: { type: Type.STRING },
                    rgb: { type: Type.STRING },
                    cmyk: { type: Type.STRING },
                    usage: { type: Type.STRING },
                  },
                  required: ["hex", "name", "rgb", "cmyk", "usage"],
                },
              },
              typography: {
                type: Type.OBJECT,
                properties: {
                  titles: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                      style: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage", "style"],
                  },
                  body: {
                    type: Type.OBJECT,
                    properties: {
                      fontFamily: { type: Type.STRING },
                      usage: { type: Type.STRING },
                      style: { type: Type.STRING },
                    },
                    required: ["fontFamily", "usage", "style"],
                  },
                },
                required: ["titles", "body"],
              },
              graphicElements: {
                type: Type.OBJECT,
                properties: {
                  patternConcept: { type: Type.STRING },
                  textureDescription: { type: Type.STRING },
                },
                required: ["patternConcept", "textureDescription"],
              },
              rules: {
                type: Type.OBJECT,
                properties: {
                  allowed: { type: Type.ARRAY, items: { type: Type.STRING } },
                  forbidden: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["allowed", "forbidden"],
              },
              visualStyle: { type: Type.STRING },
              applications: {
                type: Type.OBJECT,
                properties: {
                  socialMedia: { type: Type.STRING },
                  flyers: { type: Type.STRING },
                  businessCards: { type: Type.STRING },
                  website: { type: Type.STRING },
                },
                required: ["socialMedia", "flyers", "businessCards", "website"],
              },
            },
            required: ["colors", "typography", "graphicElements", "rules", "visualStyle", "applications"],
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              credibilityScore: { type: Type.NUMBER },
              futureRecommendations: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["credibilityScore", "futureRecommendations"]
          }
        },
        required: ["logo", "styleGuide", "analysis"],
      },
    },
  });

  return JSON.parse(response.text.trim());
};

export const generateImage = async (prompt: string, base64ReferenceImage?: string): Promise<string> => {
  const parts: any[] = [{ text: prompt }];

  if (base64ReferenceImage) {
    const cleanBase64 = base64ReferenceImage.replace(/^data:image\/\w+;base64,/, "");
    parts.unshift({
      inlineData: {
        mimeType: 'image/png',
        data: cleanBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: parts,
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Erreur de génération d'image.");
};

import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;
    const element = contentRef.current;
    const opt = {
      margin: 0,
      filename: `BrandBook_${companyName.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };
    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  const handleDownloadSourcePack = async () => {
    setIsZipping(true);
    try {
      const zip = new JSZip();
      const assetsWeb = zip.folder("01_Formats_Web_PNG_JPG");
      const assetsPrint = zip.folder("02_Formats_Print_HighRes");
      const assetsVector = zip.folder("03_Formats_Vectoriels_SVG");
      const specs = zip.folder("04_Specifications_Techniques");

      const addImage = (base64: string | undefined, name: string, folder: any) => {
        if (!base64 || !folder) return;
        folder.file(`${name}.png`, base64.split(',')[1], { base64: true });
      };

      // Distribution des images
      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_RGB", assetsWeb);
      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_CMYK_REF", assetsPrint);
      addImage(data.logo.simplifiedImageUrl, "LOGO_SIMPLIFIED", assetsWeb);
      addImage(data.logo.monochromeImageUrl, "LOGO_MONOCHROME", assetsPrint);
      addImage(data.logo.faviconImageUrl, "FAVICON_WEB", assetsWeb);
      addImage(data.styleGuide.graphicElements.patternImageUrl, "PATTERN_TEXTURE", assetsPrint);

      // Fichier Vectoriel SVG
      if (data.logo.svgPath) {
        const svgContent = `<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" fill="${data.styleGuide.colors[0].hex}">${data.logo.svgPath}</svg>`;
        assetsVector?.file("SYMBOLISME_VECTORIEL.svg", svgContent);
      }

      const designSystem = {
        identity: companyName,
        colors: data.styleGuide.colors,
        typography: data.styleGuide.typography,
        rules: data.styleGuide.rules,
        productionSpecs: {
