import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import BrandingResult from './components/BrandingResult';
import { BrandProfile, BrandingResult as BrandingType } from './types';
import { generateBranding, generateImage } from './services/geminiService';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Analyse stratégique de l'écosystème...");
    setError(null);
    try {
      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');

      setLoadingStep("Design du logotype multi-supports...");
      const logoPrompt = `High-end professional minimal vector logo for "${brandProfile.companyName}". Colors: ${colorString}. Symbol: ${brandingData.logo.description}. Pure white background, high contrast.`;
      const masterLogoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = masterLogoUrl;

      setLoadingStep("Création du motif de texture (Pattern)...");
      const patternPrompt = `Seamless high-end brand pattern. Concept: ${brandingData.styleGuide.graphicElements.patternConcept}. Colors: ${colorString}. Minimalist repeat.`;
      brandingData.styleGuide.graphicElements.patternImageUrl = await generateImage(patternPrompt, masterLogoUrl);

      setLoadingStep("Optimisation des formats Web & Print...");
      brandingData.logo.simplifiedImageUrl = await generateImage(`Minimalist avatar version of the logo in the ATTACHED image. Solid background.`, masterLogoUrl);
      brandingData.logo.monochromeImageUrl = await generateImage(`Black and white solid silhouette of the ATTACHED logo symbol. No grey.`, masterLogoUrl);
      brandingData.logo.faviconImageUrl = await generateImage(`Core central symbol of the ATTACHED image. Square, high legibility.`, masterLogoUrl);

      setLoadingStep("Calcul de la cohérence visuelle...");
      const mockupPrompt = `MASTER MOCKUP: Show the logo and pattern on premium stationery and a luxury smartphone screen. Professional studio lighting. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt, masterLogoUrl);

      setResult(brandingData);

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      console.error(err);
      setError("Erreur technique de production. Veuillez vérifier vos entrées.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
  };

  return (
    <div className="min-h-screen relative overflow-x-hidden">
      <div className="absolute top-0 left-0 w-full h-[600px] bg-indigo-950 overflow-hidden -z-10 skew-y-[-2deg] origin-top-left border-b-8 border-blue-500/20">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-950 via-indigo-900 to-blue-900 opacity-95"></div>
      </div>

      <Header />

      <main className="max-w-6xl mx-auto px-4 pb-20 relative z-10">
        <div className="text-center mb-12 py-10">
          <h2 className="text-5xl md:text-8xl font-serif text-blue-400 mb-6 drop-shadow-xl font-black">
            Identité <span className="text-white">Absolute</span>
          </h2>
          <p className="text-blue-100/90 text-xl md:text-3xl max-w-3xl mx-auto font-light leading-relaxed">
            Cohérence multi-plateforme. Crédibilité immédiate. Prestige technologique.
          </p>
        </div>

        <div className="max-w-4xl mx-auto mb-16">
          <InputForm onSubmit={handleGenerate} isLoading={isLoading} />

          {isLoading && (
            <div className="mt-12 flex flex-col items-center bg-indigo-900/50 backdrop-blur-3xl rounded-[3rem] p-12 border border-white/10 shadow-3xl">
              <div className="relative w-24 h-24 mb-8">
                <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
                <div className="absolute inset-0 border-t-4 border-blue-400 rounded-full animate-spin"></div>
              </div>
              <p className="text-blue-200 text-3xl font-black tracking-tight animate-pulse">{loadingStep}</p>
              <p className="text-blue-400/50 text-[10px] mt-4 uppercase tracking-[0.5em] font-bold">Omni-channel Production v2.1</p>
            </div>
          )}

          {error && (
            <div className="mt-8 p-8 bg-red-500/10 backdrop-blur-sm border border-red-500/20 text-red-400 rounded-3xl text-center font-bold shadow-2xl">
              {error}
            </div>
          )}
        </div>

        {result && (
          <div id="result-section" className="mt-20">
            <BrandingResult 
              data={result} 
              onUpdateMockups={handleUpdateMockups}
              companyName={profile?.companyName || ""}
            />
          </div>
        )}
      </main>

      <footer className="bg-white/5 backdrop-blur-xl border-t border-white/5 py-16 px-4 print:hidden relative z-10">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center text-[10px] font-bold uppercase tracking-widest text-blue-100/30">
