        <div className="absolute inset-0 bg-gradient-to-br from-indigo-950 via-slate-900 to-blue-950 opacity-90"></div>
        <div className="absolute top-1/4 left-1/4 w-[600px] h-[600px] bg-indigo-600/20 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-1/4 right-1/4 w-[500px] h-[500px] bg-blue-600/10 rounded-full blur-[100px] animate-pulse" style={{ animationDelay: '2s' }}></div>
      </div>

      <Header />

      <main className="flex-grow max-w-7xl mx-auto px-6 pb-32 relative z-10 w-full">
        {/* Animated Hero Section */}
        <div className={`text-center py-20 transition-all duration-1000 transform ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
          <div className="inline-block px-6 py-2 rounded-full glass-dark border-white/10 mb-8 animate-bounce-slow">
             <span className="text-[10px] font-black uppercase tracking-[0.5em] text-blue-400">Identity Master Suite v3.0</span>
          </div>

          <h2 className="text-6xl md:text-9xl font-serif text-white mb-8 font-black tracking-tighter leading-tight text-glow">
            Identité <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-400 to-purple-400 italic">Absolute</span>
          </h2>

          <p className="text-blue-100/70 text-lg md:text-3xl max-w-4xl mx-auto font-light leading-relaxed mb-12">
            Concevez une présence de marque <span className="text-white font-medium">unique</span>, <span className="text-white font-medium">cohérente</span> et <span className="text-white font-medium">omniprésente</span>. Propulsé par une IA stratégique de niveau designer senior.
          </p>

          <div className="flex flex-wrap justify-center gap-4 text-[10px] font-bold uppercase tracking-widest text-blue-300/60 mb-16">
            <span className="px-4 py-2 border border-white/5 rounded-full bg-white/5">Vector Ready</span>
