interface InputFormProps {
  onSubmit: (profile: BrandProfile) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [profile, setProfile] = useState<BrandProfile>({
    companyName: '',
    industry: '',
    mission: '',
    values: '',
    targetAudience: '',
    positioning: 'Minimaliste / Épuré',
    preferences: '',
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setProfile(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(profile);
  };

  const inputClasses = "w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-[1.5rem] focus:ring-8 focus:ring-indigo-500/10 focus:border-indigo-500 focus:bg-white transition-all outline-none text-slate-800 placeholder-slate-400 font-semibold shadow-sm text-base";
  const labelClasses = "block text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3 ml-2";

  return (
    <div className="relative group">
      {/* Dynamic Aura */}
      <div className="absolute -inset-1.5 bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 rounded-[3.2rem] blur-xl opacity-20 group-hover:opacity-40 transition duration-1000"></div>

      <form onSubmit={handleSubmit} className="relative bg-white rounded-[3rem] shadow-[0_25px_80px_-15px_rgba(0,0,0,0.1)] p-10 md:p-16 space-y-10 border border-slate-100">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-3">
            <label className={labelClasses}>Identité Commerciale</label>
            <input
              required
              name="companyName"
              value={profile.companyName}
              onChange={handleChange}
              placeholder="Ex: Luminia Tech"
              className={inputClasses}
            />
          </div>
          <div className="space-y-3">
            <label className={labelClasses}>Secteur & Marché</label>
            <input
              required
              name="industry"
              value={profile.industry}
              onChange={handleChange}
              placeholder="Ex: Énergie solaire innovante"
              className={inputClasses}
            />
          </div>
        </div>

        <div className="space-y-3">
          <label className={labelClasses}>Essence Stratégique (Vision)</label>
          <textarea
            required
            name="mission"
            value={profile.mission}
            onChange={handleChange}
            rows={3}
            placeholder="Quelle est la raison d'être unique de votre entreprise ? Quelle promesse faites-vous au monde ?"
            className={`${inputClasses} resize-none`}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-3">
            <label className={labelClasses}>Valeurs Directrices</label>
