              required
              name="values"
              value={profile.values}
              onChange={handleChange}
              placeholder="Ex: Innovation, Éthique, Excellence"
              className={inputClasses}
            />
          </div>
          <div className="space-y-3">
            <label className={labelClasses}>Archétype de Positionnement</label>
            <select
              name="positioning"
              value={profile.positioning}
              onChange={handleChange}
              className={inputClasses}
            >
              <option value="Luxe / Haut de gamme">Luxe / Haut de gamme</option>
              <option value="Moderne / Technologique">Moderne / Technologique</option>
              <option value="Accessible / Familial">Accessible / Familial</option>
              <option value="Institutionnel / Sérieux">Institutionnel / Sérieux</option>
              <option value="Minimaliste / Épuré">Minimaliste / Épuré</option>
              <option value="Créatif / Audacieux">Créatif / Audacieux</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-3">
            <label className={labelClasses}>Clientèle de Référence</label>
            <input
              required
              name="targetAudience"
              value={profile.targetAudience}
              onChange={handleChange}
              placeholder="Ex: Professionnels urbains, 25-45 ans"
              className={inputClasses}
            />
          </div>
          <div className="space-y-3">
            <label className={labelClasses}>Directives Visuelles</label>
            <input
              name="preferences"
              value={profile.preferences}
              onChange={handleChange}
              placeholder="Couleurs, symboles, styles à privilégier"
              className={inputClasses}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full relative py-7 bg-indigo-600 hover:bg-indigo-700 text-white font-black uppercase tracking-[0.2em] text-sm rounded-[1.8rem] shadow-[0_20px_50px_rgba(79,70,229,0.3)] transition-all duration-500 flex items-center justify-center overflow-hidden group/btn disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-[1.01] active:scale-95"
        >
          <span className="relative z-10 flex items-center justify-center">
            {isLoading ? (
              <>
                <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin mr-4"></div>
                Intelligence de Design en Action...
              </>
            ) : "Déclencher la Transformation de Marque"}
