          <div className="absolute inset-0 bg-gradient-to-r from-indigo-500 via-blue-600 to-purple-600 opacity-0 group-hover/btn:opacity-100 transition-opacity duration-500"></div>
          <div className="absolute inset-0 bg-white/10 translate-y-full group-hover/btn:translate-y-0 transition-transform duration-500"></div>
        </button>
      </form>
    </div>
  );
};

