// Image Generation with Pro Model & Custom Aspect Ratios
export const generateImagePro = async (prompt: string, aspectRatio: any = "1:1"): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: `High-end professional UNIQUE brand asset. Minimalist, premium, iconic. Prompt: ${prompt}` }] },
    config: { imageConfig: { aspectRatio: aspectRatio, imageSize: "1K" } }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur de génération d'image Pro.");
};

export const generateImage = async (prompt: string, base64ReferenceImage?: string): Promise<string> => {
  const ai = getAI();
  const parts: any[] = [{ text: `High-end professional UNIQUE and UNMISTAKABLE logo design. Prompt: ${prompt}` }];
  if (base64ReferenceImage) {
    const cleanBase64 = base64ReferenceImage.replace(/^data:image\/\w+;base64,/, "");
    parts.unshift({
      inlineData: { mimeType: 'image/png', data: cleanBase64 },
    });
  }
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: parts },
    config: { imageConfig: { aspectRatio: "1:1" } }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur de génération d'image.");
};

// Edit Image with Gemini 2.5 Flash Image
export const editImageWithPrompt = async (base64Image: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const cleanBase64 = base64Image.replace(/^data:image\/\w+;base64,/, "");
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: cleanBase64, mimeType: 'image/png' } },
        { text: prompt }
      ]
    }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur lors de l'édition de l'image.");
};

// Generate Video with Veo
export const generateVideoVeo = async (base64Image: string, prompt: string, isLandscape: boolean = true): Promise<string> => {
  const ai = getAI();
  const cleanBase64 = base64Image.replace(/^data:image\/\w+;base64,/, "");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: cleanBase64,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: isLandscape ? '16:9' : '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const videoBlob = await videoResponse.blob();
  return URL.createObjectURL(videoBlob);
};

