import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;
    const element = contentRef.current;
    const opt = {
      margin: 0,
      filename: `BrandIdentity_${companyName.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };
    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  const handleDownloadSourcePack = async () => {
    setIsZipping(true);
    try {
      const zip = new JSZip();
      const assetsWeb = zip.folder("01_Formats_Web_Digital");
      const assetsPrint = zip.folder("02_Formats_Print_HD");
      const assetsVector = zip.folder("03_Vectoriel_SVG");
      const socialKit = zip.folder("04_Social_Media_Kit");
      const specs = zip.folder("05_Charte_Technique");

      const addImage = (base64: string | undefined, name: string, folder: any) => {
        if (!base64 || !folder) return;
        folder.file(`${name}.png`, base64.split(',')[1], { base64: true });
      };

      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_RGB", assetsWeb);
      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_CMYK", assetsPrint);
      addImage(data.logo.faviconImageUrl, "FAVICON", assetsWeb);
      addImage(data.logo.simplifiedImageUrl, "AVATAR_SOCIAL", socialKit);
      addImage(data.styleGuide.graphicElements.patternImageUrl, "BRAND_TEXTURE", assetsPrint);

      if (data.logo.svgPath) {
        const svgContent = `<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" fill="${data.styleGuide.colors[0].hex}">${data.logo.svgPath}</svg>`;
        assetsVector?.file("LOGO_CONSTRUCTION.svg", svgContent);
      }

      const readme = `
PACK DE PRODUCTION - ${companyName}
===================================

STRATÉGIE D'UNICITÉ :
- Pourquoi c'est unique : ${data.logo.uniquenessFactor}
- Différenciation : ${data.logo.differentiationStrategy}

ÉCOSYSTÈME :
1. SOCIAL : ${data.styleGuide.ecosystem.socialMedia.avatarStyle}
2. WEB : ${data.styleGuide.ecosystem.digital.webInterface}
3. PRINT : ${data.styleGuide.ecosystem.print.businessCard}
4. PACKAGING : ${data.styleGuide.ecosystem.packaging.materialSuggestion}

IDENTITÉ PROTÉGÉE PAR LA DIFFÉRENCIATION.
`;
      specs?.file("GUIDE_TECHNIQUE.txt", readme);
      specs?.file("manifest.json", JSON.stringify(data, null, 2));

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(content);
      link.download = `Brand_Expert_Pack_${companyName}.zip`;
      link.click();
    } finally {
      setIsZipping(false);
    }
  };

  const generateExtraMockups = async () => {
    if (!data.logo.generatedImageUrl) return;
    setIsGeneratingMockups(true);
    try {
      const colorString = data.styleGuide.colors.map(c => c.hex).join(', ');
      const prompts = [
        `MOCKUP: Branding on official corporate LinkedIn/Instagram UI. Colors: ${colorString}.`,
        `MOCKUP: Luxury business card on textured paper. Minimalist typography.`,
        `MOCKUP: High-end physical packaging box with the unique logo. 3D view.`
      ];
      const results = await Promise.all(prompts.map(p => generateImage(p, data.logo.generatedImageUrl)));
      if (onUpdateMockups) onUpdateMockups(results);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGeneratingMockups(false);
    }
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20">
      <div 
        ref={contentRef} 
        id="branding-export-container" 
        className="bg-white text-indigo-950 overflow-hidden shadow-2xl md:rounded-[2rem] border border-gray-100"
        style={{ width: '100%', maxWidth: '1000px', margin: '0 auto' }}
      >
        {/* COUVERTURE HAUTE COUTURE */}
        <section className="min-h-[850px] flex flex-col justify-center items-center bg-indigo-950 text-white p-12 md:p-24 relative overflow-hidden text-center">
          <div className="relative z-10 space-y-12">
            <div className="w-28 h-28 bg-blue-600 rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl rotate-6 border-4 border-white/20">
              <span className="text-5xl font-black">B</span>
            </div>
            <div className="space-y-6">
              <h1 className="text-7xl md:text-9xl font-serif font-black tracking-tighter text-white">{companyName}</h1>
              <p className="text-3xl md:text-4xl text-blue-400 font-light tracking-[0.4em] uppercase">Identity Manifesto & Assets</p>
            </div>
            <div className="w-64 h-1 bg-gradient-to-r from-transparent via-blue-500 to-transparent mx-auto"></div>
            <div className="max-w-2xl mx-auto bg-white/5 backdrop-blur-md p-8 rounded-3xl border border-white/10">
              <p className="text-blue-100/80 text-xl font-light leading-relaxed italic">
                "Ce qui vous rend unique est votre plus grand avantage compétitif."
              </p>
            </div>
          </div>
          <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-blue-600/20 rounded-full blur-[200px] -mr-80 -mt-80"></div>
          <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-indigo-500/10 rounded-full blur-[160px] -ml-50 -mb-50"></div>
        </section>

        {/* SECTION 01: UNICITÉ & STRATÉGIE (LE PIVOT) */}
        <div className="page-break"></div>
