import { GoogleGenAI, Type, Modality } from "@google/genai";
import { BrandProfile, BrandingResult } from "../types";

// Factory function to get up-to-date instances
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const SYSTEM_INSTRUCTION = `
Tu es un Directeur Artistique Visionnaire de niveau "World-Class" et Expert en Stratégie de Différenciation.
Ton objectif absolu est l'UNICITÉ TOTALE. Une marque qui ressemble à une autre est un échec stratégique.

RÈGLES D'OR DE DIFFÉRENCIATION :
1. ANTI-CLICHÉS : Interdiction formelle d'utiliser les symboles attendus du secteur.
2. PIVOT CRÉATIF : Propose une direction radicalement innovante.
3. MÉTAPHORES ABSTRAITES : Privilégie des formes géométriques propriétaires.
4. IDENTITÉ "SIGNATURE" : Le logo doit être identifiable même en ombre chinoise.

IMPORTANT POUR LE SVG :
Tu dois fournir un 'svgPath' qui est un tracé vectoriel (D-path) complexe et professionnel. Ce tracé sera utilisé pour générer le fichier source éditable (SVG) que le client pourra ouvrir dans Photoshop, Illustrator ou Affinity Designer. Le tracé doit être continu, propre et esthétiquement parfait.
`;

export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const ai = getAI();
  const prompt = `
    Génère une identité de marque EXCLUSIVE et UNIQUE pour "${profile.companyName}".
    Secteur : ${profile.industry}
    Positionnement : ${profile.positioning}

    Tâche : Crée un concept de logo qui ne peut être confondu avec AUCUN concurrent. 
    Explique ton raisonnement stratégique.

    Inclus dans le JSON :
    - uniquenessFactor : Pourquoi ce logo est structurellement unique ?
    - differentiationStrategy : Stratégie visuelle.
    - svgPath : UN TRACÉ SVG COMPLET ET VALIDE (le contenu de l'attribut 'd' d'un <path>). Ce doit être un symbole iconique et mémorable.
    - Ecosystem (Social, Web, Print, Packaging).

    Réponds en JSON uniquement.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          logo: {
            type: Type.OBJECT,
            properties: {
              concept: { type: Type.STRING },
              type: { type: Type.STRING },
              symbolism: { type: Type.STRING },
              description: { type: Type.STRING },
              svgPath: { type: Type.STRING },
              uniquenessFactor: { type: Type.STRING },
              differentiationStrategy: { type: Type.STRING },
              variations: {
