import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import BrandingResult from './components/BrandingResult';
import AdvancedLab from './components/AdvancedLab';
import ChatBot from './components/ChatBot';
import { BrandProfile, BrandingResult as BrandingType } from './types';
import { generateBranding, generateImage, fastAnalyzeContent } from './services/geminiService';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);
  const [isVisible, setIsVisible] = useState(false);
  const [fastAnalysis, setFastAnalysis] = useState<string>("");

  useEffect(() => {
    setIsVisible(true);
  }, []);

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Analyse stratégique de l'écosystème...");
    setError(null);
    try {
      // Low latency feedback
      fastAnalyzeContent(brandProfile.mission).then(setFastAnalysis);

      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');
      const primaryColor = brandingData.styleGuide.colors[0].hex;

      setLoadingStep("Design du logotype maître...");
      const logoPrompt = `High-end professional minimal vector logo for "${brandProfile.companyName}". Colors: ${colorString}. Symbol: ${brandingData.logo.description}. Pure white background, high contrast. Unique and unmistakable style.`;
      const masterLogoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = masterLogoUrl;

      setLoadingStep("Génération des variations d'identité...");
      brandingData.logo.simplifiedImageUrl = await generateImage(`Minimalist icon-only version of the logo. Flat design. White background.`, masterLogoUrl);
      brandingData.logo.monochromeImageUrl = await generateImage(`Pure black silhouette of the logo on white background. No colors.`, masterLogoUrl);
      brandingData.logo.invertedImageUrl = await generateImage(`Logo variation: the logo is entirely white, placed on a solid background of color ${primaryColor}.`, masterLogoUrl);
      brandingData.logo.darkBgImageUrl = await generateImage(`Logo on a deep charcoal black background. Modern aesthetic.`, masterLogoUrl);
      brandingData.logo.faviconImageUrl = await generateImage(`Small square favicon version of the central symbol. High legibility.`, masterLogoUrl);

      setLoadingStep("Création du motif de texture (Pattern)...");
      const patternPrompt = `Seamless high-end brand pattern. Concept: ${brandingData.styleGuide.graphicElements.patternConcept}. Colors: ${colorString}. Minimalist repeat.`;
      brandingData.styleGuide.graphicElements.patternImageUrl = await generateImage(patternPrompt, masterLogoUrl);

      setLoadingStep("Calcul de la cohérence visuelle...");
      const mockupPrompt = `MASTER MOCKUP: Show the logo and pattern on premium stationery. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt, masterLogoUrl);

      setResult(brandingData);

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 300);
    } catch (err) {
      console.error(err);
      setError("Désolé, une erreur technique a interrompu la production. Veuillez vérifier vos crédits API.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-500 selection:text-white pb-40">
      <Header />

      <main className="flex-grow max-w-7xl mx-auto px-6 relative z-10 w-full">
        {/* Animated Hero Section */}
        <div className={`text-center py-24 transition-all duration-1000 transform ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
          <div className="inline-block px-6 py-2 rounded-full glass-dark border-white/40 mb-10 shadow-2xl">
             <span className="text-[11px] font-black uppercase tracking-[0.5em] text-blue-400">Identity Architecture • 2026</span>
          </div>

          <h2 className="text-7xl md:text-[10rem] font-serif text-white mb-10 font-black tracking-tighter leading-[0.9] text-glow-strong drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)]">
            Identité <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-300 to-white italic">Absolute</span>
          </h2>

          <p className="text-indigo-50 text-xl md:text-3xl max-w-4xl mx-auto font-medium leading-relaxed mb-16 drop-shadow-[0_4px_10px_rgba(0,0,0,0.8)]">
            Concevez une présence de marque <span className="text-white font-bold border-b-2 border-indigo-500">unique</span> et <span className="text-white font-bold border-b-2 border-indigo-500">omniprésente</span>. 
            Une cohérence totale du packaging aux réseaux sociaux.
          </p>

          <div className="flex flex-wrap justify-center gap-5 text-[11px] font-bold uppercase tracking-widest mb-20">
            <span className="px-6 py-3 border-2 border-white/20 rounded-2xl bg-indigo-950 text-white shadow-xl">Architectural Design</span>
            <span className="px-6 py-3 border-2 border-white/20 rounded-2xl bg-indigo-950 text-white shadow-xl">Multi-Channel Strategy</span>
            <span className="px-6 py-3 border-2 border-white/20 rounded-2xl bg-indigo-950 text-white shadow-xl">Vector Excellence</span>
          </div>
        </div>

        {/* Form Container */}
        <div className={`max-w-4xl mx-auto transition-all duration-1000 delay-300 transform ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0'}`}>
          <InputForm onSubmit={handleGenerate} isLoading={isLoading} />

          {isLoading && (
            <div className="mt-20 flex flex-col items-center glass-dark rounded-[4rem] p-20 border-2 border-white/20 shadow-3xl">
              <div className="w-40 h-40 mb-12 relative">
                <div className="absolute inset-0 border-[10px] border-indigo-500/20 rounded-full animate-ping"></div>
                <div className="absolute inset-0 border-[10px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
              </div>
              <p className="text-white text-4xl font-serif italic mb-4">{loadingStep}</p>
              {fastAnalysis && <p className="text-indigo-300 text-sm max-w-md text-center italic font-bold">Quick Analysis: {fastAnalysis}</p>}
            </div>
          )}

          {error && (
            <div className="mt-12 p-12 bg-white rounded-[3.5rem] border-4 border-red-500 shadow-2xl">
              <h3 className="text-2xl font-black text-red-600 mb-2 uppercase">Erreur de Stratégie</h3>
              <p className="text-slate-900 text-lg font-bold">{error}</p>
            </div>
          )}
        </div>

        {/* Master Laboratory */}
        <div className={`transition-all duration-1000 delay-500 ${isVisible ? 'opacity-100' : 'opacity-0'}`}>
           <AdvancedLab />
        </div>

        {/* Result Rendering */}
        {result && (
          <div id="result-section" className="mt-40 pt-32">
            <BrandingResult 
              data={result} 
              onUpdateMockups={handleUpdateMockups}
              companyName={profile?.companyName || ""}
            />
          </div>
        )}
      </main>

      <ChatBot />

      <footer className="bg-black border-t-4 border-indigo-900 py-32 px-10 relative overflow-hidden mt-40">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center text-[12px] font-black uppercase tracking-[0.6em] text-white gap-10">
          <p>© 2026 BrandGenius Global Lab.</p>
          <div className="flex gap-12">
            <span>Instagram</span>
            <span>LinkedIn</span>
            <span>Dribbble</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const getSVGContent = () => {
    if (!data.logo.svgPath) return null;
    return `<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" fill="${data.styleGuide.colors[0].hex}"><path d="${data.logo.svgPath}" /></svg>`;
  };

  const handleDownloadSVG = () => {
    const svgContent = getSVGContent();
    if (!svgContent) return;
    const blob = new Blob([svgContent], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
