      const readme = `
PACK DE PRODUCTION - ${companyName}
===================================
CE PACK CONTIENT LES FICHIERS SOURCES POUR PHOTOSHOP, AFFINITY OU ILLUSTRATOR.

STRATÉGIE D'UNICITÉ :
- Pourquoi c'est unique : ${data.logo.uniquenessFactor}
- Différenciation : ${data.logo.differentiationStrategy}

ÉCOSYSTÈME :
1. SOCIAL : ${data.styleGuide.ecosystem.socialMedia.avatarStyle}
2. WEB : ${data.styleGuide.ecosystem.digital.webInterface}
3. PRINT : ${data.styleGuide.ecosystem.print.businessCard}
4. PACKAGING : ${data.styleGuide.ecosystem.packaging.materialSuggestion}

IDENTITÉ PROTÉGÉE PAR LA DIFFÉRENCIATION.
`;
      specs?.file("GUIDE_TECHNIQUE.txt", readme);
      specs?.file("manifest.json", JSON.stringify(data, null, 2));

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(content);
      link.download = `Brand_Expert_Pack_${companyName}.zip`;
      link.click();
    } finally {
      setIsZipping(false);
    }
  };

  const generateExtraMockups = async () => {
    if (!data.logo.generatedImageUrl) return;
    setIsGeneratingMockups(true);
    try {
      const colorString = data.styleGuide.colors.map(c => c.hex).join(', ');
      const prompts = [
        `MOCKUP: Branding on official corporate LinkedIn/Instagram UI. Colors: ${colorString}.`,
        `MOCKUP: Luxury business card on textured paper. Minimalist typography.`,
        `MOCKUP: High-end physical packaging box with the unique logo. 3D view.`,
        `MOCKUP: Professional office entrance sign, brushed aluminum texture with the logo embossed.`,
        `MOCKUP: Luxury smartphone app splash screen with the logo and the pattern in the background.`
      ];
      const results = await Promise.all(prompts.map(p => generateImage(p, data.logo.generatedImageUrl)));
      if (onUpdateMockups) onUpdateMockups(results);
