import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  // Helper function to clean the SVG path from potential AI hallucinations
  const getCleanPath = (rawPath: string | undefined): string => {
    if (!rawPath) return "";
    // If the model output a full tag or garbage, try to extract just the d attribute
    if (rawPath.includes('d="')) {
      const match = rawPath.match(/d="([^"]+)"/);
      return match ? match[1] : "";
    }
    // Remove any potential tags if model returned <path d="...">
    return rawPath.replace(/<[^>]*>/g, '').trim();
  };

  const cleanSvgPath = getCleanPath(data.logo.svgPath);

  const getSVGContent = () => {
    if (!cleanSvgPath) return null;
    return `<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" fill="${data.styleGuide.colors[0].hex}"><path d="${cleanSvgPath}" /></svg>`;
  };

  const handleDownloadSVG = () => {
    const svgContent = getSVGContent();
    if (!svgContent) return;
    const blob = new Blob([svgContent], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SOURCE_VECTORIELLE_${companyName.replace(/\s+/g, '_')}.svg`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;
    const element = contentRef.current;
    const opt = {
      margin: 0,
      filename: `BrandIdentity_${companyName.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };
    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  const handleDownloadSourcePack = async () => {
    setIsZipping(true);
    try {
      const zip = new JSZip();
      const assetsWeb = zip.folder("01_Formats_Web_Digital");
      const assetsPrint = zip.folder("02_Formats_Print_HD");
      const assetsVector = zip.folder("03_Vectoriel_SVG");
      const socialKit = zip.folder("04_Social_Media_Kit");
      const specs = zip.folder("05_Charte_Technique");

      const addImage = (base64: string | undefined, name: string, folder: any) => {
        if (!base64 || !folder) return;
        folder.file(`${name}.png`, base64.split(',')[1], { base64: true });
      };

      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_RGB", assetsWeb);
      addImage(data.logo.generatedImageUrl, "LOGO_MASTER_CMYK", assetsPrint);
      addImage(data.logo.faviconImageUrl, "FAVICON", assetsWeb);
      addImage(data.logo.simplifiedImageUrl, "AVATAR_SOCIAL", socialKit);
      addImage(data.logo.invertedImageUrl, "LOGO_INVERTED", assetsWeb);
      addImage(data.logo.darkBgImageUrl, "LOGO_DARK_BG", assetsWeb);
      addImage(data.styleGuide.graphicElements.patternImageUrl, "BRAND_TEXTURE", assetsPrint);

      const svgContent = getSVGContent();
      if (svgContent) {
        assetsVector?.file("SOURCE_VECTORIELLE_EDITABLE.svg", svgContent);
      }

      const readme = `
PACK DE PRODUCTION - ${companyName}
===================================
CE PACK CONTIENT LES FICHIERS SOURCES POUR PHOTOSHOP, AFFINITY OU ILLUSTRATOR.

IDENTITÉ PROTÉGÉE PAR LA DIFFÉRENCIATION.
`;
      specs?.file("GUIDE_TECHNIQUE.txt", readme);
      specs?.file("manifest.json", JSON.stringify(data, null, 2));

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(content);
      link.download = `Brand_Expert_Pack_${companyName}.zip`;
      link.click();
    } finally {
      setIsZipping(false);
    }
  };

  const generateExtraMockups = async () => {
    if (!data.logo.generatedImageUrl) return;
    setIsGeneratingMockups(true);
    try {
      const colorString = data.styleGuide.colors.map(c => c.hex).join(', ');
      const prompts = [
        `MOCKUP: Branding on official corporate LinkedIn/Instagram UI. Colors: ${colorString}.`,
        `MOCKUP: Luxury business card on textured paper. Minimalist typography.`,
