          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
             {/* BLUEPRINT VIEW */}
             <div className="space-y-8">
                <div className="bg-[#0f172a] rounded-[2.5rem] p-12 aspect-square relative flex items-center justify-center overflow-hidden border-4 border-indigo-900 shadow-2xl group">
                   {/* Grille technique */}
                   <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #3b82f6 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
                   <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'linear-gradient(#3b82f6 1px, transparent 1px), linear-gradient(90deg, #3b82f6 1px, transparent 1px)', backgroundSize: '48px 48px' }}></div>

                   {/* Le SVG avec tracés techniques */}
                   <div className="relative z-10 w-full h-full flex items-center justify-center">
                    {cleanSvgPath ? (
                      <svg viewBox="0 0 512 512" className="w-full h-full overflow-visible" xmlns="http://www.w3.org/2000/svg">
                        {/* Lignes de construction automatiques */}
                        <circle cx="256" cy="256" r="220" fill="none" stroke="#3b82f6" strokeWidth="1" strokeDasharray="8,4" opacity="0.3" />
