                        <line x1="256" y1="0" x2="256" y2="512" stroke="#3b82f6" strokeWidth="1" strokeDasharray="4,4" opacity="0.2" />

                        {/* Tracé principal style Blueprint */}
                        <path d={cleanSvgPath} fill="none" stroke="#60a5fa" strokeWidth="10" strokeLinejoin="round" strokeLinecap="round" opacity="0.3" />
