                        {/* Points d'ancrage simulés */}
                        <circle cx="256" cy="256" r="4" fill="#3b82f6" />
                      </svg>
                    ) : null}
                   </div>
                   <div className="absolute bottom-8 left-8 right-8 flex justify-between text-[8px] font-mono text-blue-400 uppercase tracking-widest opacity-60">
                     <span>GRID_SYS_V2.0</span>
                     <span>RATIO_GOLDEN_1.618</span>
