                    </div>
                  </div>
                </div>

                {/* ZONE D'EXCLUSION */}
                <div className="bg-indigo-50 rounded-3xl p-8 space-y-6">
                   <h3 className="text-xs font-black text-indigo-600 uppercase tracking-widest">Zone d'Exclusion (Safe Area)</h3>
                   <div className="flex items-center gap-10">
                      <div className="w-32 h-32 bg-white border-2 border-dashed border-indigo-200 rounded-xl relative flex items-center justify-center">
                        <div className="absolute inset-2 border border-indigo-100 bg-indigo-50/50 rounded-lg"></div>
                        <img src={data.logo.faviconImageUrl} className="w-12 h-12 opacity-80" />
                        <div className="absolute top-0 left-0 w-2 h-2 bg-indigo-400"></div>
