  companyName: string;
  industry: string;
  mission: string;
  values: string;
  targetAudience: string;
  positioning: string;
  preferences: string;
}

export interface BrandingResult {
  logo: {
    concept: string;
    type: string;
    symbolism: string;
    description: string;
    svgPath?: string;
    uniquenessFactor: string;
    differentiationStrategy: string;
    variations: {
      color: string;
      black: string;
      white: string;
      backgrounds: string;
    };
    generatedImageUrl?: string;
    simplifiedImageUrl?: string;
    monochromeImageUrl?: string;
    faviconImageUrl?: string;
    socialAvatarUrl?: string;
    invertedImageUrl?: string;
    darkBgImageUrl?: string;
  };
  styleGuide: {
    colors: Array<{
      hex: string;
      name: string;
      rgb: string;
      cmyk: string;
      usage: string;
    }>;
    typography: {
