}

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import BrandingResult from './components/BrandingResult';
import AdvancedLab from './components/AdvancedLab';
import ChatBot from './components/ChatBot';
import { BrandProfile, BrandingResult as BrandingType } from './types';
import { generateBranding, generateImage, fastAnalyzeContent, generateVideoVeo } from './services/geminiService';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>("");
  const [result, setResult] = useState<BrandingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [profile, setProfile] = useState<BrandProfile | null>(null);
  const [isVisible, setIsVisible] = useState(false);
  const [fastAnalysis, setFastAnalysis] = useState<string>("");

  useEffect(() => {
    setIsVisible(true);
  }, []);

  const checkKey = async () => {
    // @ts-ignore
    if (window.aistudio && !(await window.aistudio.hasSelectedApiKey())) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }
  };

  const handleGenerate = async (brandProfile: BrandProfile) => {
    setIsLoading(true);
    setProfile(brandProfile);
    setLoadingStep("Analyse stratégique de l'écosystème...");
    setError(null);
    try {
      fastAnalyzeContent(brandProfile.mission).then(setFastAnalysis);

      const brandingData = await generateBranding(brandProfile);
      const colorString = brandingData.styleGuide.colors.map(c => c.hex).join(', ');
      const primaryColor = brandingData.styleGuide.colors[0].hex;

      setLoadingStep("Design du logotype maître...");
      const logoPrompt = `High-end professional minimal vector logo for "${brandProfile.companyName}". Colors: ${colorString}. Symbol: ${brandingData.logo.description}. Pure white background, high contrast. Unique and unmistakable style.`;
      const masterLogoUrl = await generateImage(logoPrompt);
      brandingData.logo.generatedImageUrl = masterLogoUrl;

      setLoadingStep("Génération des variations d'identité...");
      brandingData.logo.simplifiedImageUrl = await generateImage(`Minimalist icon-only version of the logo. Flat design. White background.`, masterLogoUrl);
      brandingData.logo.monochromeImageUrl = await generateImage(`Pure black silhouette of the logo on white background. No colors.`, masterLogoUrl);
      brandingData.logo.invertedImageUrl = await generateImage(`Logo variation: the logo is entirely white, placed on a solid background of color ${primaryColor}.`, masterLogoUrl);
      brandingData.logo.darkBgImageUrl = await generateImage(`Logo on a deep charcoal black background. Modern aesthetic.`, masterLogoUrl);
      brandingData.logo.faviconImageUrl = await generateImage(`Small square favicon version of the central symbol. High legibility.`, masterLogoUrl);

      setLoadingStep("Production de la cinématique de marque (Veo)...");
      try {
        await checkKey();
        const videoPrompt = `Vidéo promotionnelle courte et dynamique pour le logo de ${brandProfile.companyName}. Utilise les couleurs primaires : ${brandingData.styleGuide.colors[0].hex}, ${brandingData.styleGuide.colors[1]?.hex || 'white'}. Style : ${brandingData.styleGuide.visualStyle}. Met en avant le logo de manière moderne et percutante.`;
        brandingData.styleGuide.ecosystem.promoVideoUrl = await generateVideoVeo(masterLogoUrl, videoPrompt, true);
      } catch (videoErr) {
        console.warn("Échec de la génération vidéo Veo, passage à la suite.", videoErr);
      }

      setLoadingStep("Création du motif de texture (Pattern)...");
      const patternPrompt = `Seamless high-end brand pattern. Concept: ${brandingData.styleGuide.graphicElements.patternConcept}. Colors: ${colorString}. Minimalist repeat.`;
      brandingData.styleGuide.graphicElements.patternImageUrl = await generateImage(patternPrompt, masterLogoUrl);

      setLoadingStep("Calcul de la cohérence visuelle...");
      const mockupPrompt = `MASTER MOCKUP: Show the logo and pattern on premium stationery. Colors: ${colorString}.`;
      brandingData.styleGuide.mockupImageUrl = await generateImage(mockupPrompt, masterLogoUrl);

      setResult(brandingData);

      setTimeout(() => {
        document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 300);
    } catch (err) {
      console.error(err);
      setError("Désolé, une erreur technique a interrompu la production. Veuillez vérifier vos crédits API.");
    } finally {
      setIsLoading(false);
      setLoadingStep("");
    }
  };

  const handleUpdateMockups = (mockups: string[]) => {
    if (result) {
      setResult({
        ...result,
        styleGuide: {
          ...result.styleGuide,
          extraMockups: mockups
        }
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-500 selection:text-white pb-40">
      <Header />

      <main className="flex-grow max-w-7xl mx-auto px-6 relative z-10 w-full">
        <div className={`text-center py-24 transition-all duration-1000 transform ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
          <div className="inline-block px-6 py-2 rounded-full glass-dark border-white/40 mb-10 shadow-2xl">
             <span className="text-[11px] font-black uppercase tracking-[0.5em] text-blue-400">Identity Architecture • 2026</span>
          </div>

          <h2 className="text-7xl md:text-[10rem] font-serif text-white mb-10 font-black tracking-tighter leading-[0.9] text-glow-strong drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)]">
            Identité <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-300 to-white italic">Absolute</span>
          </h2>

          <p className="text-indigo-50 text-xl md:text-3xl max-w-4xl mx-auto font-medium leading-relaxed mb-16 drop-shadow-[0_4px_10px_rgba(0,0,0,0.8)]">
            Concevez une présence de marque <span className="text-white font-bold border-b-2 border-indigo-500">unique</span> et <span className="text-white font-bold border-b-2 border-indigo-500">omniprésente</span>. 
          </p>
        </div>

        <div className={`max-w-4xl mx-auto transition-all duration-1000 delay-300 transform ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0'}`}>
          <InputForm onSubmit={handleGenerate} isLoading={isLoading} />

          {isLoading && (
            <div className="mt-20 flex flex-col items-center glass-dark rounded-[4rem] p-20 border-2 border-white/20 shadow-3xl">
              <div className="w-40 h-40 mb-12 relative">
                <div className="absolute inset-0 border-[10px] border-indigo-500/20 rounded-full animate-ping"></div>
                <div className="absolute inset-0 border-[10px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
              </div>
              <p className="text-white text-4xl font-serif italic mb-4">{loadingStep}</p>
              {fastAnalysis && <p className="text-indigo-300 text-sm max-w-md text-center italic font-bold">Quick Analysis: {fastAnalysis}</p>}
            </div>
          )}

          {error && (
            <div className="mt-12 p-12 bg-white rounded-[3.5rem] border-4 border-red-500 shadow-2xl">
              <h3 className="text-2xl font-black text-red-600 mb-2 uppercase">Erreur de Stratégie</h3>
              <p className="text-slate-900 text-lg font-bold">{error}</p>
            </div>
          )}
        </div>

        <div className={`transition-all duration-1000 delay-500 ${isVisible ? 'opacity-100' : 'opacity-0'}`}>
           <AdvancedLab />
        </div>

        {result && (
          <div id="result-section" className="mt-40 pt-32">
            <BrandingResult 
              data={result} 
              onUpdateMockups={handleUpdateMockups}
              companyName={profile?.companyName || ""}
            />
          </div>
        )}
      </main>

      <ChatBot />

      <footer className="bg-black border-t-4 border-indigo-900 py-32 px-10 relative overflow-hidden mt-40">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center text-[12px] font-black uppercase tracking-[0.6em] text-white gap-10">
          <p>© 2026 BrandGenius Global Lab.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage } from '../services/geminiService';
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isGeneratingMockups, setIsGeneratingMockups] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const getCleanPath = (rawPath: string | undefined): string => {
    if (!rawPath) return "";
    if (rawPath.includes('d="')) {
      const match = rawPath.match(/d="([^"]+)"/);
      return match ? match[1] : "";
    }
    return rawPath.replace(/<[^>]*>/g, '').trim();
  };

  const cleanSvgPath = getCleanPath(data.logo.svgPath);

  const getSVGContent = () => {
    if (!cleanSvgPath) return null;
    return `<svg width="512" height="512" viewBox="0 0 512 512" xmlns="http://www.w3.org/2000/svg" fill="${data.styleGuide.colors[0].hex}"><path d="${cleanSvgPath}" /></svg>`;
  };

  const handleDownloadSVG = () => {
    const svgContent = getSVGContent();
    if (!svgContent) return;
    const blob = new Blob([svgContent], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SOURCE_VECTORIELLE_${companyName.replace(/\s+/g, '_')}.svg`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;
    const element = contentRef.current;
    const opt = {
      margin: 0,
      filename: `BrandIdentity_${companyName.replace(/\s+/g, '_')}.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };
    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  const handleDownloadSourcePack = async () => {
    setIsZipping(true);
    try {
      const zip = new JSZip();
      const assetsVector = zip.folder("03_Vectoriel_SVG");
      const assetsMotion = zip.folder("06_Motion_Assets");

      const svgContent = getSVGContent();
      if (svgContent) {
        assetsVector?.file("SOURCE_MASTER.svg", svgContent);
      }

      if (data.styleGuide.ecosystem.promoVideoUrl) {
        // Since we can't easily fetch and base64 a remote blob in this zip context without more setup,
        // we'll at least leave a pointer or instructions if the direct fetch is restricted.
        assetsMotion?.file("README_MOTION.txt", `Vidéo promotionnelle disponible à: ${data.styleGuide.ecosystem.promoVideoUrl}`);
      }

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(content);
      link.download = `Pack_Complet_${companyName}.zip`;
      link.click();
    } finally {
      setIsZipping(false);
    }
  };

  return (
    <div className="space-y-16 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20">
      <div 
        ref={contentRef} 
        id="branding-export-container" 
        className="bg-white text-indigo-950 overflow-hidden shadow-2xl md:rounded-[3rem] border border-gray-100"
        style={{ width: '100%', maxWidth: '1100px', margin: '0 auto' }}
      >
        {/* COUVERTURE */}
        <section className="min-h-[800px] flex flex-col justify-center items-center bg-indigo-950 text-white p-12 relative overflow-hidden text-center">
          <div className="relative z-10 space-y-8">
            <div className="w-24 h-24 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto shadow-2xl border-2 border-white/20">
              <span className="text-4xl font-black">B</span>
            </div>
            <h1 className="text-6xl md:text-8xl font-serif font-black tracking-tighter text-white uppercase">{companyName}</h1>
            <p className="text-2xl text-blue-400 font-light tracking-[0.5em] uppercase">Brand Identity Guide</p>
          </div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-blue-600/10 via-transparent to-transparent opacity-50"></div>
        </section>

        {/* SECTION 01: LOGO & GÉOMÉTRIE */}
        <div className="page-break"></div>
        <section className="p-12 md:p-20 bg-white space-y-24">
          <div className="flex items-end gap-6 border-b border-gray-100 pb-8">
            <span className="text-8xl font-serif text-indigo-50 font-black leading-none">01</span>
            <div>
              <h2 className="text-4xl font-bold text-indigo-950 uppercase tracking-tighter">Construction & Tracés</h2>
              <p className="text-blue-600 font-bold tracking-[0.3em] uppercase text-[10px]">L'ADN Vectoriel du Symbole</p>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
             <div className="space-y-8">
                <div className="bg-[#0f172a] rounded-[2.5rem] p-12 aspect-square relative flex items-center justify-center overflow-hidden border-4 border-indigo-900 shadow-2xl group">
                   <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #3b82f6 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
                   <div className="relative z-10 w-full h-full flex items-center justify-center">
                    {cleanSvgPath ? (
                      <svg viewBox="0 0 512 512" className="w-full h-full overflow-visible" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="256" cy="256" r="220" fill="none" stroke="#3b82f6" strokeWidth="1" strokeDasharray="8,4" opacity="0.3" />
                        <path d={cleanSvgPath} fill="none" stroke="#60a5fa" strokeWidth="10" strokeLinejoin="round" strokeLinecap="round" opacity="0.3" />
                        <path d={cleanSvgPath} fill="none" stroke="#3b82f6" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
                      </svg>
                    ) : null}
                   </div>
                </div>
                <div className="px-6 space-y-4">
                  <h3 className="text-xl font-bold text-indigo-950 uppercase">Rigueur Mathématique</h3>
                  <p className="text-sm text-slate-500 italic">"Chaque courbe est calculée pour assurer un équilibre parfait."</p>
                </div>
             </div>

             <div className="space-y-12">
                <div className="grid grid-cols-2 gap-8">
                  <div className="space-y-4">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Version Maître</p>
                    <div className="aspect-video bg-gray-50 rounded-2xl flex items-center justify-center p-6 border border-gray-100 shadow-inner">
                      <img src={data.logo.generatedImageUrl} className="max-h-full object-contain" />
                    </div>
                  </div>
                </div>
                <div className="bg-indigo-50 rounded-3xl p-8 space-y-6">
                   <h3 className="text-xs font-black text-indigo-600 uppercase tracking-widest">Zone d'Exclusion</h3>
                   <div className="flex items-center gap-10">
                      <div className="w-24 h-24 bg-white border-2 border-dashed border-indigo-200 rounded-xl relative flex items-center justify-center">
                        <img src={data.logo.faviconImageUrl} className="w-10 h-10 opacity-80" />
                      </div>
                      <p className="text-[11px] text-indigo-900/60 leading-relaxed font-medium">Zone d'exclusion égale à 20% de la hauteur du symbole.</p>
                   </div>
                </div>
             </div>
          </div>
        </section>

        {/* SECTION 02: MODE D'UTILISATION */}
        <div className="page-break"></div>
        <section className="p-12 md:p-20 bg-gray-50 space-y-20">
          <div className="flex items-end gap-6 border-b border-gray-200 pb-8">
            <span className="text-8xl font-serif text-gray-100 font-black leading-none">02</span>
            <div>
              <h2 className="text-4xl font-bold text-indigo-950 uppercase tracking-tighter">Usage & Maintenance</h2>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
             <div className="bg-white rounded-[3rem] p-12 shadow-sm border border-gray-200 space-y-6">
                <h3 className="text-xl font-bold text-emerald-600 uppercase flex items-center gap-4">Autorisé</h3>
                <ul className="space-y-4 text-sm text-slate-600 font-bold">
                   {data.styleGuide.rules.allowed.map((rule, i) => <li key={i}>✓ {rule}</li>)}
                </ul>
             </div>
             <div className="bg-white rounded-[3rem] p-12 shadow-sm border border-gray-200 space-y-6">
                <h3 className="text-xl font-bold text-red-600 uppercase flex items-center gap-4">Interdit</h3>
                <ul className="space-y-4 text-sm text-slate-600 font-bold">
                   {data.styleGuide.rules.forbidden.map((rule, i) => <li key={i}>✕ {rule}</li>)}
                </ul>
             </div>
          </div>
        </section>

        {/* SECTION 03: ÉCOSYSTÈME VISUEL & BANNIÈRES DYNAMIQUES */}
        <div className="page-break"></div>
        <section className="p-12 md:p-20 bg-white space-y-24">
          <div className="flex items-end gap-6 border-b border-gray-100 pb-8">
            <span className="text-8xl font-serif text-gray-50 font-black leading-none">03</span>
            <div>
              <h2 className="text-4xl font-bold text-indigo-950 uppercase tracking-tighter">Écosystème Visuel</h2>
              <p className="text-blue-600 font-bold tracking-[0.3em] uppercase text-[10px]">Déploiement Multi-supports</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
             <div className="bg-indigo-950 text-white p-10 rounded-[2.5rem] space-y-4">
                <p className="text-[10px] font-black text-blue-400 uppercase">Digital</p>
                <p className="text-sm font-light italic">"{data.styleGuide.ecosystem.digital.webInterface}"</p>
             </div>
             <div className="bg-slate-50 text-indigo-950 p-10 rounded-[2.5rem] space-y-4 border border-slate-200">
                <p className="text-[10px] font-black text-indigo-400 uppercase">Print</p>
                <p className="text-sm font-light italic">"{data.styleGuide.ecosystem.print.businessCard}"</p>
             </div>
             <div className="bg-blue-600 text-white p-10 rounded-[2.5rem] space-y-4">
                <p className="text-[10px] font-black text-white/60 uppercase">Social</p>
                <p className="text-sm font-light italic">"{data.styleGuide.ecosystem.socialMedia.avatarStyle}"</p>
             </div>
          </div>

          {/* SOUS-SECTION: BANNIÈRES DYNAMIQUES (NOUVEAUTÉ) */}
          <div className="space-y-12 pt-12">
            <div className="flex items-center justify-between border-b border-gray-100 pb-6">
              <h3 className="text-2xl font-black text-indigo-950 uppercase tracking-tighter">Bannières Dynamiques</h3>
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-4 py-1 rounded-full">Powered by Veo 3.1</span>
            </div>

            <div className="relative group">
              <div className="bg-black rounded-[3.5rem] overflow-hidden shadow-3xl aspect-video border-8 border-indigo-900/20 relative group">
                {data.styleGuide.ecosystem.promoVideoUrl ? (
                  <video 
                    src={data.styleGuide.ecosystem.promoVideoUrl} 
                    className="w-full h-full object-cover" 
                    autoPlay 
                    loop 
                    muted 
                    playsInline
                  />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center space-y-4 bg-slate-900">
                    <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                    <p className="text-[10px] text-white/40 font-black uppercase tracking-widest">Calcul de la cinématique...</p>
                  </div>
                )}

                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-12">
                   <div className="space-y-2">
                      <p className="text-white font-bold text-xl uppercase tracking-tighter">Motion Master Asset</p>
                      <p className="text-white/60 text-xs font-medium italic">Animation publicitaire 1080p pour affichage digital.</p>
                   </div>
                </div>
              </div>

              <div className="mt-8 flex items-start gap-12">
                <div className="flex-1 space-y-4">
                  <p className="text-xs font-black text-indigo-400 uppercase tracking-widest">Concept Motion</p>
                  <p className="text-sm text-slate-600 leading-relaxed font-medium">
                    Une vidéo promotionnelle courte et dynamique pour le logo de {companyName}. 
                    Met en avant le logo de manière moderne et percutante avec des transitions fluides basées sur le style "{data.styleGuide.visualStyle}".
                  </p>
                </div>
                <div className="flex-shrink-0">
                  <a 
                    href={data.styleGuide.ecosystem.promoVideoUrl} 
                    download={`Promo_${companyName}.mp4`}
                    className="px-6 py-3 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all inline-flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    Exporter MP4
                  </a>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* SECTION 04: CODES COULEURS */}
        <div className="page-break"></div>
        <section className="p-12 md:p-20 bg-white space-y-20">
