        <path d="${cleanSvgPath}" id="Logo-Path" fill="${data.styleGuide.colors[0].hex}"></path>
    </g>
</svg>`;
    const blob = new Blob([svgHeader], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${companyName.replace(/\s+/g, '_')}_MASTER_SOURCE.svg`;
    link.click();
    URL.revokeObjectURL(url);
